from PIL import Image, ImageFilter, ImageOps

def load_image(path):
    return Image.open(path)

def convert_to_grayscale(image):
    return image.convert('L')

def crop_image(image, size):
    width, height = image.size
    left = (width - size[0])/2
    top = (height - size[1])/2
    right = (width + size[0])/2
    bottom = (height + size[1])/2

    return image.crop((left, top, right, bottom))

def rotate_image(image, angle):
    return image.rotate(angle)

def flip_image(image, direction):
    if direction == 'horizontal':
        return image.transpose(Image.FLIP_LEFT_RIGHT)
    elif direction == 'vertical':
        return image.transpose(Image.FLIP_TOP_BOTTOM)
    else:
        print("Invalid direction! Use 'horizontal' or 'vertical'")
        return image

def smooth_image(image):
    return image.filter(ImageFilter.SMOOTH)

def detect_edges(image):
    return image.filter(ImageFilter.FIND_EDGES)

# Ví dụ cách sử dụng các chức năng
if __name__ == "main":
    img_path = 'image/1.jpg' # Thay thế đường dẫn đến ảnh của bạn
    image = load_image(img_path)

    # Convert to grayscale
    grayscale_image = convert_to_grayscale(image)
    grayscale_image.show()

    # Crop image to 200x200
    cropped_image = crop_image(image, (200, 200))
    cropped_image.show()

    # Rotate image by 90 degrees
    rotated_image = rotate_image(image, 90)
    rotated_image.show()

    # Flip image horizontally
    flipped_image = flip_image(image, 'horizontal')
    flipped_image.show()

    # Smooth image
    smoothed_image = smooth_image(grayscale_image) # Smooth chỉ áp dụng tốt trên ảnh xám
    smoothed_image.show()

    # Detect edges
    edges_image = detect_edges(grayscale_image)
    edges_image.show()

To create a Flask application that uses OpenCV to perform various image processing tasks like reading an image, converting it to grayscale, cropping, rotating, flipping, smoothing (denoising), and edge detection, you can follow the steps below:

First, make sure you have Flask and OpenCV installed:

```bash
pip install Flask opencv-python-headless
```

Now, you can write a Flask application that provides these functionalities. For simplicity, I'll create an application with endpoints that perform these operations individually. A production-ready app should include proper error handling and additional features like input validation.

Here's an example Flask application doing the required tasks:

```python
from flask import Flask, request, send_file
import cv2
import numpy as np
from tempfile import NamedTemporaryFile

app = Flask(__name__)

@app.route('/read-image', methods=['POST'])
def read_image():
    if 'file' not in request.files:
        return "No file part", 400
    file = request.files['file']
    if file.filename == '':
        return "No selected file", 400
    image = cv2.imdecode(np.fromstring(file.read(), np.uint8), cv2.IMREAD_UNCHANGED)
    return process_image(image)

@app.route('/convert-to-grayscale', methods=['POST'])
def convert_to_grayscale():
    image = get_image_from_request(request)
    grayscale_image = cv2.cvtColor(image, cv2.COLOR_BGR2GRAY)
    return process_image(grayscale_image)

@app.route('/crop-image', methods=['POST'])
def crop_image():
    image = get_image_from_request(request)
    h, w = image.shape[:2]
    cropped_image = image[h//4:h*3//4, w//4:w*3//4]
    return process_image(cropped_image)

@app.route('/rotate-image', methods=['POST'])
def rotate_image():
    image = get_image_from_request(request)
    angle = request.form.get("angle", default=0, type=int)
    rotate_matrix = cv2.getRotationMatrix2D(center=(w / 2, h / 2), angle=angle, scale=1)
    rotated_image = cv2.warpAffine(image, rotate_matrix, (w, h))
    return process_image(rotated_image)

@app.route('/flip-image', methods=['POST'])
def flip_image():
    image = get_image_from_request(request)
    flip_mode = request.form.get("mode", default=1, type=int)  # 0 for vertical, 1 for horizontal flip
    flipped_image = cv2.flip(image, flip_mode)
    return process_image(flipped_image)

@app.route('/smooth-image', methods=['POST'])
def smooth_image():
    image = get_image_from_request(request)
    smooth_image = cv2.GaussianBlur(image, (5, 5), 0)
    return process_image(smooth_image)

@app.route('/detect-edges', methods=['POST'])
def detect_edges():
    image = get_image_from_request(request)
    edges_image = cv2.Canny(image, 100, 200)
    return process_image(edges_image)

def get_image_from_request(request):
    if 'file' not in request.files:
        raise ValueError("No file part")
    file = request.files['file']
    if file.filename == '':
        raise ValueError("No selected file")
    image = cv2.imdecode(np.fromstring(file.read(), np.uint8), cv2.IMREAD_UNCHANGED)
    return image

def process_image(image):
    is_success, buffer = cv2.imencode(".jpg", image)
    if not is_success:
        return "Could not process image", 500
    with NamedTemporaryFile(delete=False) as temp_file:
        temp_file.write(buffer)
        temp_file.flush()
        return send_file(temp_file.name, mimetype='image/jpeg', as_attachment=True)

if __name__ == '__main__':
    app.run(debug=True)
```

In the code above, each endpoint performs a specific operation on the uploaded image and then sends the processed image back as a response. The `get_image_from_request` function extracts the image data from the incoming request, and `process_image` converts the OpenCV image back into a JPEG to be returned in the HTTP response.

To use these endpoints, you would send a POST request to the desired endpoint with the image file included in the request. For example, to convert an image to grayscale, you would POST the image file to `/convert-to-grayscale`.

Keep in mind that for simplicity, I'm using `NamedTemporaryFile` to temporarily store the processed image file to send it as a response. In a production environment, it's better to use more persistent and secure methods for handling files.
